/**
 * /api/export-pdf  (v6 — Layout fixes + Directory Page)
 * Patch over v5. Targeted changes:
 *  - CSS: A4 margins normalised, KPI flex, table overflow, email word-wrap, TAM waterfall
 *  - HTML: Directory Section Guide injected as Page 2 (base64 embedded PNG)
 *  - No Step 1–7 logic changes · No API contract changes
 */
import { verifyAuth, corsHeaders, validate, errRes } from './_middleware.js';

export async function onRequestPost(context) {
  const { request, env } = context;
  const cors = corsHeaders(env);
  if (request.method === 'OPTIONS') return new Response(null, { status: 204, headers: cors });
  const { user, error: authErr } = await verifyAuth(request, env);
  if (!user) return errRes(authErr || 'Unauthorized', 401, cors);
  let body;
  try { body = await request.json(); } catch { return errRes('Invalid request body', 400, cors); }
  const errors = validate({ strategy: 'required' }, body);
  if (errors.length) return errRes(errors[0], 400, cors);
  const { strategy } = body;
  if (!strategy.company_name) return errRes('Missing strategy.company_name', 400, cors);

  const QC = {
    enabled: (env?.QUICKCHART_ENABLED ?? 'true') !== 'false',
    apiKey:  env?.QUICKCHART_API_KEY || '',
    timeout: parseInt(env?.QUICKCHART_TIMEOUT_MS) || 5000,
    maxPer:  parseInt(env?.QUICKCHART_MAX_PER_REPORT) || 5,
  };

  const isDemoMode = !!(
    strategy.demo_mode || strategy.report_mode === 'demo' ||
    strategy._profile_source === 'demo_mode_simulated' ||
    strategy.step_7_intelligence?.demo_mode ||
    (strategy.step_1_market?.analyst_insight||'').toLowerCase().includes('demo mode')
  );

  const charts = { gauge: null, waterfall: null, confidence: null, intent: null, risk: null };
  if (QC.enabled) {
    const s2 = strategy.step_2_tam || {};
    const s7 = strategy.step_7_intelligence || {};
    const s1 = strategy.step_1_market || {};
    const gtmScore = parseInt(
      s1.gtm_relevance_score ||
      s7.score_breakdown?.total ||
      s7.gtm_score ||
      strategy.gtm_score
    ) || (isDemoMode ? 60 : 0);
    const verdict = s7.go_no_go?.recommendation ||
      s7.verdict || strategy.verdict ||
      (gtmScore>=75?'Go':gtmScore>=50?'Watch':'No-Go') ||
      (isDemoMode ? 'Watch' : 'Watch');
    const confScore = parseInt(
      s7.confidence_score || s7.overall_fidelity || s7._data_quality?.confidence_after_cap
    ) || gtmScore || (isDemoMode ? 60 : 0);

    const tamRaw = safe_val(s2.tam_size_estimate); const tamNum = parseMoneyValue(tamRaw, isDemoMode ? 1800 : 0);
    const samRaw = safe_val(s2.sam_estimate || s2.waterfall?.sam_value);
    const samNum = samRaw && samRaw !== '—' ? parseMoneyValue(samRaw, tamNum * 0.4) : tamNum * 0.4;
    const somRawVal = safe_val(s2.waterfall?.som_value || '');
    const somIsPercent = somRawVal && /\d+.*%/.test(somRawVal);
    const somNum = (!somRawVal || somIsPercent) ? tamNum * 0.07 : parseMoneyValue(somRawVal, tamNum * 0.07);

    const formatUSD = n => { if(n>=1000) return `USD ${(n/1000).toFixed(1).replace(/\.0$/,'')}B`; if(n>0) return `USD ${Math.round(n)}M`; return 'USD 0'; };
    s2.tam_size_estimate = formatUSD(tamNum);
    s2.sam_estimate = formatUSD(samNum);
    if (!s2.waterfall) s2.waterfall = {};
    s2.waterfall.tam_value = formatUSD(tamNum);
    s2.waterfall.sam_value = formatUSD(samNum);
    s2.waterfall.som_value = formatUSD(somNum);

    const liveVeracity     = safeNumber(s7.signal_veracity     || s7.confidence_breakdown?.signal_veracity,     0);
    const liveTiming       = safeNumber(s7.market_timing       || s7.confidence_breakdown?.market_timing,       0);
    const liveIcpFit       = safeNumber(s7.icp_fit             || s7.confidence_breakdown?.icp_fit,             0);
    const liveCompleteness = safeNumber(s7.data_completeness   || s7.confidence_breakdown?.data_completeness,   0);
    const hasLiveSubs = liveVeracity > 0 || liveTiming > 0 || liveIcpFit > 0 || liveCompleteness > 0;
    const matrixVeracity     = hasLiveSubs ? liveVeracity     : Math.round(confScore * 0.4);
    const matrixTiming       = hasLiveSubs ? liveTiming       : Math.round(confScore * 0.25);
    const matrixIcpFit       = hasLiveSubs ? liveIcpFit       : Math.round(confScore * 0.2);
    const matrixCompleteness = hasLiveSubs ? liveCompleteness : Math.round(confScore * 0.15);

    let chartCount = 0;
    const tryFetch = async (type, config, w, h) => {
      if (chartCount >= QC.maxPer) { console.warn(`[QuickChart] max calls (${QC.maxPer}) reached — fallback for ${type}`); return null; }
      chartCount++;
      try { return await fetchQuickChartBase64(config, w, h, QC, type); }
      catch(err) { console.warn(`[QuickChart] ${type} fallback triggered:`, err.message); return null; }
    };

    const [g, wf, cm] = await Promise.allSettled([
      tryFetch('gauge',      buildGtmGaugeChartConfig(gtmScore, verdict), 320, 200),
      tryFetch('waterfall',  buildTamWaterfallChartConfig(tamNum, samNum, somNum), 760, 280),
      tryFetch('confidence', buildConfidenceMatrixChartConfig({
        veracity: matrixVeracity, timing: matrixTiming,
        icpFit: matrixIcpFit, completeness: matrixCompleteness,
        overall: confScore
      }), 760, 300),
    ]);
    charts.gauge      = g.status==='fulfilled'  ? g.value  : null;
    charts.waterfall  = wf.status==='fulfilled' ? wf.value : null;
    charts.confidence = cm.status==='fulfilled' ? cm.value : null;

    const _s5 = strategy.step_5_keywords || strategy.steps?.[5] || {};
    const _arr = v => Array.isArray(v)?v:(v?[String(v)]:[]);
    const intentSignals = _arr(_s5?.intent_signals||_s5?.intent_topics||[]);
    const intentItems = intentSignals.slice(0,4).map((s,i)=>({
      label: typeof s==='string'?s:(s.signal||s.label||`Signal ${i+1}`),
      strength: typeof s==='object'&&s.strength ? s.strength : [72,58,65,50][i]||60
    }));
    const [intent, risk] = await Promise.allSettled([
      tryFetch('intent', buildIntentSignalChartConfig(intentItems), 480, 180),
      tryFetch('risk',   buildRiskSeverityChartConfig(verdict, gtmScore), 480, 180),
    ]);
    charts.intent = intent.status==='fulfilled' ? intent.value : null;
    charts.risk   = risk.status==='fulfilled'   ? risk.value   : null;
    console.info(`[QuickChart] total calls=${chartCount}/${QC.maxPer} gauge=${!!charts.gauge} waterfall=${!!charts.waterfall} confidence=${!!charts.confidence} intent=${!!charts.intent} risk=${!!charts.risk}`);
  }

  const filename = `GTM_${strategy.company_name.replace(/[^a-zA-Z0-9]/g, '_')}_${new Date().toISOString().slice(0, 10)}.pdf`;
  const renderMode = body.renderMode || 'browser-pdf';
  const html = buildReportHTML(strategy, charts, isDemoMode, renderMode);
  return new Response(JSON.stringify({ html, filename, mode: renderMode }), {
    status: 200, headers: { ...cors, 'Content-Type': 'application/json' },
  });
}

export async function onRequestOptions(context) {
  return new Response(null, { status: 204, headers: corsHeaders(context.env) });
}

// ══════════════════════════════════════════════════════════════
// QUICKCHART HELPERS (unchanged from v5)
// ══════════════════════════════════════════════════════════════

function safeNumber(value, fallback = 0) {
  if (value === null || value === undefined || value === '') return fallback;
  const n = parseFloat(String(value).replace(/[^0-9.\-]/g, ''));
  return isNaN(n) ? fallback : n;
}

function renderChartOrFallback(type, base64, fallbackHtml, dimensions = { width: 480, height: 180 }) {
  if (base64) {
    return `<div style="margin:2.5mm 0;line-height:0">
      <img src="data:image/png;base64,${base64}"
        width="${dimensions.width}" height="${dimensions.height}"
        style="width:100%;max-height:${dimensions.height}px;object-fit:contain;border-radius:7px"
        alt="${type} chart"/>
    </div>`;
  }
  return fallbackHtml;
}

function normalizeCompanyName(name) {
  if (!name) return 'Company';
  let n = String(name).trim();
  n = n.replace(/^[\. ]+|[\. ]+$/g, '');
  if (n === n.toLowerCase()) n = n.charAt(0).toUpperCase() + n.slice(1);
  return n || 'Company';
}

function safe_val(v) {
  if (!v && v !== 0) return '';
  if (Array.isArray(v)) return v.join(', ');
  if (typeof v === 'object') return Object.values(v).join(', ');
  return String(v);
}

function parseMoneyValue(str, fallback = 0) {
  if (!str) return fallback;
  const s = String(str).replace(/,/g,'').toUpperCase();
  const m = s.match(/([\d.]+)\s*(B|M|K)?/);
  if (!m) return fallback;
  const n = parseFloat(m[1]);
  const unit = m[2] || '';
  if (unit === 'B') return n * 1000;
  if (unit === 'M') return n;
  if (unit === 'K') return n / 1000;
  return n > 1000 ? n / 1e6 : n;
}

function buildGtmGaugeChartConfig(score, verdict) {
  const pct = Math.max(0, Math.min(100, parseInt(score) || 0));
  const color = /^go$/i.test(verdict) ? '#22c55e' : /no/i.test(verdict) ? '#ef4444' : '#f59e0b';
  const verLabel = /^go$/i.test(verdict) ? 'GO' : /no/i.test(verdict) ? 'NO-GO' : 'WATCH';
  return {
    type: 'doughnut',
    data: {
      labels: ['Score', 'Remaining'],
      datasets: [
        { data: [100], backgroundColor: ['rgba(255,255,255,0.04)'], borderWidth: 0, circumference: 220, rotation: 250, cutout: '82%', radius: '100%' },
        { data: [pct, 100 - pct], backgroundColor: [color, 'rgba(255,255,255,0.06)'], borderWidth: 0, circumference: 220, rotation: 250, cutout: '70%', radius: '88%' },
      ],
    },
    options: {
      responsive: false, maintainAspectRatio: false, animation: false,
      layout: { padding: 10 },
      plugins: {
        legend: { display: false }, tooltip: { enabled: false },
        doughnutlabel: { labels: [
          { text: String(pct), font: { size: 36, weight: '900', family: 'monospace' }, color: '#ffffff' },
          { text: verLabel, font: { size: 13, weight: '800', family: 'Inter, sans-serif' }, color: color },
          { text: 'GTM SCORE', font: { size: 8, weight: '600', family: 'Inter, sans-serif' }, color: '#9CA3AF' },
        ]},
      },
    },
  };
}

function buildTamWaterfallChartConfig(tamM, samM, somM) {
  const safeNum = v => (Number.isFinite(v) && v > 0) ? v : 0;
  const values = [safeNum(tamM), safeNum(samM), safeNum(somM)];
  const maxVal = Math.max(100, ...values) * 1.22;
  const fmt = v => { const n = Number(v)||0; if(n>=1000) return 'USD '+(n/1000).toFixed(1).replace(/\.0$/,'')+'B'; if(n>0) return 'USD '+Math.round(n)+'M'; return 'USD 0'; };
  const somPct = values[0]>0 ? Math.round((values[2]/values[0])*100) : 0;
  return {
    type: 'bar',
    data: {
      labels: ['Total Addressable\nMarket (TAM)', 'Serviceable\nAvailable (SAM)', 'Serviceable\nObtainable (SOM)'],
      datasets: [{ label: '', data: values, backgroundColor: ['#6366f1', '#8b5cf6', '#f59e0b'], borderRadius: 10, borderSkipped: false, barThickness: 30, maxBarThickness: 38 }]
    },
    options: {
      responsive: false, maintainAspectRatio: false, animation: false,
      indexAxis: 'y',
      layout: { padding: { right: 30, left: 10, top: 16, bottom: 16 } },
      plugins: {
        legend: { display: false }, tooltip: { enabled: false },
        datalabels: { display: true, color: '#ffffff', font: { size: 11, weight: '700', family: 'monospace' }, anchor: 'end', align: 'right', offset: 4,
          formatter: function(v) { var n=Number(v)||0; if(n>=1000) return 'USD '+(n/1000).toFixed(1).replace(/\.0$/,'')+'B'; if(n>=1) return 'USD '+Math.round(n)+'M'; return n>0?'USD '+n:'USD 0'; } },
        annotation: { annotations: {
          captureZone: { type:'line', xMin:values[2]>0?values[2]:values[0]*0.07, xMax:values[2]>0?values[2]:values[0]*0.07, borderColor:'rgba(245,158,11,0.5)', borderWidth:1.5, borderDash:[4,3],
            label: { enabled:true, content:somPct>0?`Capture Zone ~${somPct}%`:'Capture Zone', position:'start', backgroundColor:'rgba(245,158,11,0.12)', color:'#f59e0b', font:{size:9,weight:'600'}, padding:{x:4,y:2}, xAdjust:0, yAdjust:-16 } },
          aiNote: { type:'label', xValue:maxVal*0.01, yValue:2.48, content:['AI-estimated · validate with analyst data'], color:'rgba(156,163,175,0.7)', font:{size:8,style:'italic'} },
        }},
      },
      scales: {
        x: { beginAtZero:true, min:0, max:Math.round(maxVal), ticks:{color:'#9CA3AF',font:{size:9},callback:v=>fmt(v)}, grid:{color:'rgba(255,255,255,0.06)',drawBorder:false} },
        y: { ticks:{color:'#E5E7EB',font:{size:10,weight:'700'},autoSkip:false,maxRotation:0,minRotation:0}, grid:{display:false} }
      },
    }
  };
}

function buildConfidenceMatrixChartConfig({ veracity, timing, icpFit, completeness, overall }) {
  const safe = v => { const n=Number(v); return Number.isFinite(n)?Math.max(0,Math.min(100,Math.round(n))):0; };
  const toPercent = (sc, max) => safe(Math.round((sc/max)*100));
  const values = [toPercent(veracity,40),toPercent(timing,25),toPercent(icpFit,20),toPercent(completeness,15),safe(overall)];
  const overallColor = values[4]>=75?'#22c55e':values[4]>=50?'#f59e0b':'#ef4444';
  const bgColors = ['#7c3aed','#8b5cf6','#6366f1','#a78bfa',overallColor];
  return {
    type:'bar',
    data:{ labels:['Signal Veracity (40%)','Market Timing (25%)','ICP Fit (20%)','Data Completeness (15%)','Overall Fidelity'],
      datasets:[{label:'',data:values,backgroundColor:bgColors,borderRadius:8,borderSkipped:false,barThickness:20,maxBarThickness:26}]},
    options:{
      responsive:false,maintainAspectRatio:false,animation:false,indexAxis:'y',
      layout:{padding:{right:30,left:10,top:14,bottom:14}},
      plugins:{legend:{display:false},tooltip:{enabled:false},
        datalabels:{display:true,color:function(ctx){return ctx.dataIndex===4?'#ffffff':'rgba(255,255,255,0.85)';},font:function(ctx){return{size:ctx.dataIndex===4?12:10,weight:'700',family:'monospace'};},anchor:'end',align:'right',offset:4,formatter:function(v,ctx){if(ctx.dataIndex===4)return v+'/100';return v+'%';}},
        annotation:{annotations:{weakLine:{type:'line',xMin:50,xMax:50,borderColor:'rgba(245,158,11,0.35)',borderWidth:1.5,borderDash:[3,3],label:{enabled:true,content:'Validate',position:'start',backgroundColor:'rgba(245,158,11,0.08)',color:'#f59e0b',font:{size:8,weight:'600'},padding:{x:4,y:2},yAdjust:-14}},strongLine:{type:'line',xMin:75,xMax:75,borderColor:'rgba(34,197,94,0.30)',borderWidth:1.5,borderDash:[3,3],label:{enabled:true,content:'Strong',position:'start',backgroundColor:'rgba(34,197,94,0.08)',color:'#22c55e',font:{size:8,weight:'600'},padding:{x:4,y:2},yAdjust:-14}}}}},
      scales:{x:{beginAtZero:true,min:0,max:110,ticks:{color:'#9CA3AF',font:{size:9},callback:v=>v<=100?v+'%':''},grid:{color:'rgba(255,255,255,0.06)',drawBorder:false}},y:{ticks:{color:'#E5E7EB',font:{size:9,weight:'600'},autoSkip:false,maxRotation:0},grid:{display:false}}}
    }
  };
}

function arrayBufferToBase64(buffer) {
  let binary = '';
  const bytes = new Uint8Array(buffer);
  const chunkSize = 8192;
  for (let i = 0; i < bytes.length; i += chunkSize) { binary += String.fromCharCode.apply(null, bytes.slice(i, i + chunkSize)); }
  return btoa(binary);
}

async function withTimeout(promise, ms) {
  return Promise.race([promise, new Promise((_, rej) => setTimeout(() => rej(new Error(`Timeout after ${ms}ms`)), ms))]);
}

async function fetchQuickChartBase64(config, width, height, qc, chartType = 'default') {
  const versionMap = { gauge:['4','3'], waterfall:['3','4'], confidence:['4','3'], intent:['4','3'], risk:['4','3'] };
  const versions = versionMap[chartType] || ['4','3'];
  const configStr = JSON.stringify(config);
  const hasDatalabels = configStr.includes('datalabels');
  const hasAnnotation = configStr.includes('annotation');
  const hasDoughnutlabel = configStr.includes('doughnutlabel');
  console.info(`[QuickChart] type=${chartType} w=${width} h=${height} datalabels=${hasDatalabels} annotation=${hasAnnotation} doughnutlabel=${hasDoughnutlabel}`);
  let lastError = null;
  for (const version of versions) {
    const payload = JSON.stringify({ chart:config, width, height, backgroundColor:'#0B0F1A', format:'png', version, ...(qc.apiKey?{key:qc.apiKey}:{}) });
    try {
      const res = await withTimeout(fetch('https://quickchart.io/chart', { method:'POST', headers:{'Content-Type':'application/json'}, body:payload }), qc.timeout);
      if (!res.ok) { const errBody = await res.text().catch(()=>''); throw new Error(`QuickChart HTTP ${res.status}: ${errBody.slice(0,80)}`); }
      const buf = await res.arrayBuffer();
      const b64 = arrayBufferToBase64(buf);
      if (!b64 || b64.length < 200) throw new Error('QuickChart returned empty image');
      console.info(`[QuickChart] ${chartType} v${version} success (${b64.length} chars)`);
      return b64;
    } catch (err) { lastError = err; console.warn(`[QuickChart] ${chartType} v${version} failed:`, err.message); }
  }
  console.warn(`[QuickChart] ${chartType} all versions failed — using fallback`);
  throw lastError || new Error('QuickChart failed');
}

function buildIntentSignalChartConfig(signals) {
  const defaults = [{label:'High buyer research',strength:72},{label:'Decision-maker outreach',strength:58},{label:'Funnel velocity',strength:65}];
  const items = (Array.isArray(signals)&&signals.length>=2)?signals.slice(0,4):defaults;
  const labels = items.map(s=>typeof s==='string'?s:(s.label||String(s)));
  const values = items.map(s=>typeof s==='object'&&s.strength?s.strength:65);
  return { type:'bar', data:{labels,datasets:[{data:values,backgroundColor:values.map(v=>v>=70?'#22c55e':v>=50?'#f59e0b':'#ef4444'),borderRadius:6,borderSkipped:false,barThickness:14,maxBarThickness:20}]},
    options:{responsive:false,maintainAspectRatio:false,animation:false,indexAxis:'y',layout:{padding:{right:28,left:8,top:8,bottom:8}},
      plugins:{legend:{display:false},tooltip:{enabled:false},datalabels:{display:true,color:'#ffffff',font:{size:9,weight:'700',family:'monospace'},anchor:'end',align:'right',offset:3,formatter:function(v){return v+'%';}}},
      scales:{x:{beginAtZero:true,min:0,max:110,ticks:{color:'#6B7280',font:{size:8},callback:v=>v<=100?v+'%':''},grid:{color:'rgba(255,255,255,0.05)',drawBorder:false}},y:{ticks:{color:'#E5E7EB',font:{size:9,weight:'600'},autoSkip:false,maxRotation:0},grid:{display:false}}}}};
}

function buildRiskSeverityChartConfig(verdict, score) {
  const cycle=score>=75?35:score>=50?65:85, lock=score>=75?40:score>=50?60:75, budget=score>=75?45:score>=50?65:80, compete=score>=75?50:score>=50?55:70;
  return { type:'bar', data:{labels:['Decision Cycle','Vendor Lock-in','Budget Friction','Competitive Pressure'],datasets:[{data:[cycle,lock,budget,compete],backgroundColor:[cycle>=70?'#ef4444':cycle>=50?'#f59e0b':'#22c55e',lock>=70?'#ef4444':lock>=50?'#f59e0b':'#22c55e',budget>=70?'#ef4444':budget>=50?'#f59e0b':'#22c55e',compete>=70?'#ef4444':compete>=50?'#f59e0b':'#22c55e'],borderRadius:6,borderSkipped:false,barThickness:14,maxBarThickness:20}]},
    options:{responsive:false,maintainAspectRatio:false,animation:false,indexAxis:'y',layout:{padding:{right:28,left:8,top:8,bottom:8}},
      plugins:{legend:{display:false},tooltip:{enabled:false},datalabels:{display:true,color:'#ffffff',font:{size:9,weight:'700',family:'monospace'},anchor:'end',align:'right',offset:3,formatter:function(v){return v>=70?'High':v>=50?'Med':'Low';}},annotation:{annotations:{highThreshold:{type:'line',xMin:70,xMax:70,borderColor:'rgba(239,68,68,0.3)',borderWidth:1,borderDash:[3,3]}}}},
      scales:{x:{beginAtZero:true,min:0,max:110,display:false},y:{ticks:{color:'#E5E7EB',font:{size:9,weight:'600'},autoSkip:false,maxRotation:0},grid:{display:false}}}}};
}

// ── Fallback renderers ──
function renderGaugeFallback(score, verdict) {
  const color = /^go$/i.test(verdict)?'var(--green)':/no/i.test(verdict)?'var(--red)':'var(--amber)';
  const circ = 157, filled = Math.round((score/100)*circ);
  return `<svg width="130" height="80" viewBox="0 0 130 80" xmlns="http://www.w3.org/2000/svg">
    <defs><linearGradient id="gaugeGrad2" x1="0%" y1="0%" x2="100%" y2="0%"><stop offset="0%" stop-color="#7c3aed"/><stop offset="100%" stop-color="${color}"/></linearGradient></defs>
    <path d="M 15 72 A 50 50 0 0 1 115 72" fill="none" stroke="rgba(255,255,255,0.08)" stroke-width="8" stroke-linecap="round"/>
    <path d="M 15 72 A 50 50 0 0 1 115 72" fill="none" stroke="url(#gaugeGrad2)" stroke-width="8" stroke-linecap="round" stroke-dasharray="${filled} ${circ}"/>
    <text x="65" y="65" text-anchor="middle" font-family="monospace" font-size="22" font-weight="900" fill="white">${score}</text>
    <text x="65" y="78" text-anchor="middle" font-family="sans-serif" font-size="7" fill="#6B7280" letter-spacing="1.5">GTM SCORE</text>
  </svg>`;
}

function renderWaterfallFallback(tamV, samV, somV) {
  const bar = (label,val,w,cls) => `<div style="display:flex;align-items:center;margin-bottom:2.5mm">
    <div style="width:90px;font-family:monospace;font-size:9.5px;text-align:right;padding-right:2.5mm;color:white;font-weight:700;flex-shrink:0;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${val}</div>
    <div style="flex:1;background:rgba(255,255,255,.08);border-radius:5px;height:13px;overflow:hidden"><div style="height:100%;border-radius:5px;width:${w}" class="${cls}"></div></div>
    <span style="margin-left:2mm;font-size:8.5px;color:#6B7280;flex-shrink:0">${label}</span>
  </div>`;
  return `<div style="margin:2.5mm 0">${bar('TAM',tamV,'80%','wfb')}${bar('SAM',samV,'50%','wfa')}${bar('SOM',somV,'20%','wfm')}</div>`;
}

function renderConfidenceFallback(v, t, f, c, overall) {
  const cmBar = (label, sc, max) => `<div style="margin-bottom:3mm">
    <div style="display:flex;justify-content:space-between;margin-bottom:1mm">
      <span style="font-size:8.5px;font-weight:700;text-transform:uppercase;letter-spacing:.1em;color:#6B7280">${label}</span>
      <span style="font-family:monospace;font-size:10.5px;font-weight:900;color:#a855f7">${sc}<span style="font-size:7.5px;font-weight:400;color:#6B7280">/${max}</span></span>
    </div>
    <div style="background:rgba(255,255,255,.07);border-radius:4px;height:8px;overflow:hidden">
      <div style="height:100%;border-radius:4px;background:linear-gradient(90deg,#7c3aed,#a855f7);width:${Math.round((sc/max)*100)}%;min-width:3px"></div>
    </div>
  </div>`;
  return cmBar('Signal Veracity (40%)',v,40)+cmBar('Market Timing (25%)',t,25)+cmBar('ICP Fit (20%)',f,20)+cmBar('Data Completeness (15%)',c,15)+
    `<div style="border-top:1px solid rgba(168,85,247,.2);margin:2.5mm 0"></div>`+
    `<div style="margin-bottom:2mm"><div style="display:flex;justify-content:space-between;margin-bottom:1mm"><span style="font-size:10px;font-weight:900;color:white">Overall Fidelity</span><span style="font-family:monospace;font-size:13px;font-weight:900;color:white">${overall}<span style="font-size:7.5px;font-weight:400;color:#6B7280">/100</span></span></div><div style="background:rgba(168,85,247,.12);border:1px solid rgba(168,85,247,.2);border-radius:5px;height:12px;overflow:hidden"><div style="height:100%;border-radius:5px;background:linear-gradient(90deg,#5b21b6,#7c3aed,#a855f7,#c084fc);width:${overall}%;min-width:3px"></div></div></div>`;
}

function escapeHtml(value) {
  return String(value || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/\s+/g, ' ').trim();
}
function truncateWords(text, limit = 70) {
  const words = String(text).trim().split(/\s+/).filter(Boolean);
  return words.length <= limit ? words.join(' ') : `${words.slice(0, limit).join(' ')}...`;
}
function safeText(value) {
  if (!value) return '';
  if (Array.isArray(value)) return value.filter(Boolean).join(', ');
  if (typeof value === 'object') return Object.values(value).filter(Boolean).join(', ');
  return String(value).trim();
}

function renderGaugeChart(base64, score, verdict, dimensions = { width: 280, height: 170 }) {
  if (!base64) return renderGaugeFallback(score, verdict);
  return `<div style="position:relative;width:${dimensions.width}px;height:${dimensions.height}px;margin:2.5mm auto;">
    <img src="data:image/png;base64,${base64}"
      width="${dimensions.width}" height="${dimensions.height}"
      style="width:100%;height:100%;object-fit:contain;border-radius:12px;"
      alt="GTM Score gauge"/>
  </div>`;
}

function renderPageInsight(title, text, isDemoMode) {
  if (!text) return '';
  const clean = truncateWords(escapeHtml(text), 70);
  const final = isDemoMode && !/demo mode/i.test(clean) ? `${clean} In demo mode, validate with live data.` : clean;
  return `<div class="page-insight"><div class="pi-title">${escapeHtml(title)}</div><div class="pi-text">${final}</div></div>`;
}

function renderExpandedPageInsight(insight, isDemoMode) {
  if (!insight || !insight.title || !insight.what_this_means || !insight.recommended_action) return renderPageInsight(insight?.title, insight?.text, isDemoMode);
  const what = truncateWords(escapeHtml(insight.what_this_means), 60);
  const action = truncateWords(escapeHtml(insight.recommended_action), 60);
  const demoNote = isDemoMode ? '<div class="pi-demo">In demo mode, validate with live data.</div>' : '';
  return `<div class="page-insight pi-expanded"><div class="pi-title">${escapeHtml(insight.title)}</div><div class="pi-grid"><div><div class="mini-label">What this means</div><p>${what}</p></div><div><div class="mini-label">Recommended action</div><p>${action}</p></div></div>${demoNote}</div>`;
}


